package ui.employer;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import dao.*;import model.*;import util.*;import ui.common.TableStyle;
public class ManageInternshipsPanel extends JPanel{ JTable table=new JTable(); public ManageInternshipsPanel(){setBackground(UITheme.BG);setLayout(new BorderLayout());add(UITheme.title("Manage Posted Internships"),BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER);load();} void load(){DefaultTableModel m=new DefaultTableModel(new Object[]{"ID","Title","City","Status","Deadline"},0); Employer emp=new EmployerDAO().getByUserId(Session.getUserId()); Company co=emp==null?null:new CompanyDAO().getByEmployerId(emp.getId()); if(co!=null) for(Internship j:new InternshipController().byCompany(co.getId()))m.addRow(new Object[]{j.getId(),j.getTitle(),j.getCity(),j.getStatus(),j.getDeadline()}); table.setModel(m);TableStyle.apply(table);} }
